# AbidjanDeals — Fix imports + store + manifest
$dest = Split-Path -Parent $MyInvocation.MyCommand.Path
Write-Host "Correction des erreurs de build..." -ForegroundColor Cyan
New-Item -ItemType Directory -Force -Path (Join-Path $dest "public") | Out-Null

$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path $dest "src\app\layout.tsx"), $b)
Write-Host "  OK src/app/layout.tsx" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path $dest "src\app\page.tsx"), $b)
Write-Host "  OK src/app/page.tsx" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path $dest "src\app\category\page.tsx"), $b)
Write-Host "  OK src/app/category/page.tsx" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path $dest "src\app\dashboard\page.tsx"), $b)
Write-Host "  OK src/app/dashboard/page.tsx" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path $dest "src\components\Navbar.tsx"), $b)
Write-Host "  OK src/components/Navbar.tsx" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path $dest "src\components\AdsSection.tsx"), $b)
Write-Host "  OK src/components/AdsSection.tsx" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path $dest "src\lib\store.ts"), $b)
Write-Host "  OK src/lib/store.ts" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path $dest "public\manifest.json"), $b)
Write-Host "  OK public/manifest.json" -ForegroundColor Green

Write-Host ""
Write-Host "Corrections appliquees !" -ForegroundColor Green
Read-Host "Appuyez sur Entree pour fermer"